--
-- Table structure for table `fiscalizacoes`
--

DROP TABLE IF EXISTS `fiscalizacoes`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `fiscalizacoes` (
  `id` varchar(15) NOT NULL,
  `nome` text DEFAULT NULL,
  `status` text DEFAULT NULL,
  `municipio` text DEFAULT NULL,
  `cpf_cnpj` varchar(30) DEFAULT NULL,
  `diretoria` text DEFAULT NULL,
  `ugrhi` varchar(100) DEFAULT NULL,
  `fiscal` text DEFAULT NULL,
  `data_fiscalizacao` date DEFAULT NULL,
  `coordenadas` text DEFAULT NULL,
  `usos` text DEFAULT NULL,
  `autos_fisc` text DEFAULT NULL,
  `autos_soe` text DEFAULT NULL,
  `processo_sei` text DEFAULT NULL,
  `auto_inspecao` text DEFAULT NULL,
  `auto_infracao` text DEFAULT NULL,
  `enquadramento` text DEFAULT NULL,
  `prazo_dias` varchar(10) DEFAULT NULL,
  `data_envio` date DEFAULT NULL,
  `numero_ar` text DEFAULT NULL,
  `data_entrega` date DEFAULT NULL,
  `situacao_entrega` text DEFAULT NULL,
  `data_manifest` date DEFAULT NULL,
  `requerimento` text DEFAULT NULL,
  `num_requerimento` text DEFAULT NULL,
  `vai_multar` text DEFAULT NULL,
  `boletim` varchar(255) DEFAULT NULL,
  `fotos` text DEFAULT NULL,
  `created` datetime NOT NULL DEFAULT current_timestamp(),
  `updated` datetime NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `deleted_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_status` (`status`(50)),
  KEY `idx_municipio` (`municipio`(100)),
  KEY `idx_fiscal` (`fiscal`(100)),
  KEY `idx_nome` (`nome`(100)),
  KEY `idx_deleted_updated` (`deleted_at`,`updated`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

