--
-- Table structure for table `indeferimentos`
--

DROP TABLE IF EXISTS `indeferimentos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `indeferimentos` (
  `id` varchar(15) NOT NULL,
  `num_requerimento` varchar(60) DEFAULT NULL,
  `status` varchar(80) DEFAULT NULL,
  `portaria` varchar(30) DEFAULT NULL,
  `data_publicacao` date DEFAULT NULL,
  `diretoria` varchar(20) DEFAULT NULL,
  `motivo` varchar(120) DEFAULT NULL,
  `num_processo` varchar(30) DEFAULT NULL,
  `nome` varchar(200) DEFAULT NULL,
  `municipio` varchar(80) DEFAULT NULL,
  `tipo_requerimento` varchar(200) DEFAULT NULL,
  `notificar` varchar(10) DEFAULT NULL,
  `data_prazo` date DEFAULT NULL,
  `novo_requerimento` varchar(10) DEFAULT NULL,
  `data_inicio_boletim` date DEFAULT NULL,
  `fiscal` varchar(100) DEFAULT NULL,
  `num_oficio` varchar(40) DEFAULT NULL,
  `auto_inspecao` varchar(40) DEFAULT NULL,
  `auto_infracao` varchar(40) DEFAULT NULL,
  `enquadramento` text DEFAULT NULL,
  `data_envio` date DEFAULT NULL,
  `numero_ar` varchar(30) DEFAULT NULL,
  `data_entrega` date DEFAULT NULL,
  `situacao_entrega` varchar(60) DEFAULT NULL,
  `requerimento` varchar(10) DEFAULT NULL,
  `num_req_novo` varchar(60) DEFAULT NULL,
  `acao_final` varchar(30) DEFAULT NULL,
  `boletim` varchar(200) DEFAULT NULL,
  `created` datetime DEFAULT NULL,
  `updated` datetime DEFAULT NULL,
  `deleted_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_deleted_updated` (`deleted_at`,`updated`),
  KEY `idx_status` (`status`),
  KEY `idx_municipio` (`municipio`),
  KEY `idx_fiscal` (`fiscal`),
  KEY `idx_nome` (`nome`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

